#include<bits/stdc++.h>
using namespace std;
const int inf=1e9;
int n,m;
double Money[2005];
int vis[2005];
vector<pair<int,double> >edge[2005];
set<pair<double,int> >q;
int main()
{
	cin>>n>>m;
	for(int i=0;i<m;i++){
		int x,y;
		double z;
		cin>>x>>y>>z;
		edge[y].push_back({x,z});
		edge[x].push_back({y,z});
	}
	int s,e;
	cin>>s>>e;
	for(int i=1;i<=n;i++)Money[i]=inf;
	Money[e]=100;
	q.insert({100,e});
	while(q.size()){
		int x=q.begin()->second;
		q.erase(q.begin());
		if(vis[x])continue;
		else vis[x]=1;
		for(auto i:edge[x]){
			int to=i.first;
			double w=i.second;
			if(Money[to]>Money[x]/(1-w/100)){
				Money[to]=Money[x]/(1-w/100);
				q.insert({Money[to],to});
			}
		}
	}
	printf("%.8f",Money[s]);
}
